// Parse the GitHub push event payload
const payload = $input.first().json;

// Check if this is a "Ping" event from GitHub
if (payload.zen) {
  return [{ json: { skip: true, reason: 'GitHub Ping received successfully!' } }];
}

const commits = payload.commits || [];
const sqlFiles = [];

for (const commit of commits) {
  const allFiles = [
    ...(commit.added || []),
    ...(commit.modified || [])
  ];

  for (const file of allFiles) {
    // Catch any .sql file anywhere
    if (file.toLowerCase().endsWith('.sql')) {
      sqlFiles.push({
        filename: file,
        sha: commit.id,
        repo: payload.repository?.full_name || '',
        branch: payload.ref?.replace('refs/heads/', '') || 'main',
        pusher: payload.pusher?.name || 'unknown'
      });
    }
  }
}

if (sqlFiles.length === 0) {
  return [{ 
    json: {
      skip: true, 
      reason: 'No .sql files found in this push.',
      payload_summary: {
        has_commits: commits.length > 0,
        repo: payload.repository?.full_name
      }
    } 
  }];
}

return sqlFiles.map(f => ({ json: f }));

// Merge SQL content + manifest context into a single prompt payload
const sqlContent = $('Fetch SQL File from GitHub').first().json.body || $('Fetch SQL File from GitHub').first().json;
const manifestRaw = $('Fetch manifest.json from GitHub').first().json.body || $('Fetch manifest.json from GitHub').first().json;
const fileInfo = $('Parse Push Event & Filter SQL Files').first().json;

let manifest = {};
try {
  manifest = typeof manifestRaw === 'string' ? JSON.parse(manifestRaw) : manifestRaw;
} catch(e) {
  manifest = {};
}

// Derive model name from filename
const modelName = fileInfo.filename
  .split('/')
  .pop()
  .replace('.sql', '');

// Find this model's node in manifest
const nodes = manifest.nodes || {};
const modelKey = Object.keys(nodes).find(k => k.includes(`model.`) && k.endsWith(`.${modelName}`));
const modelNode = modelKey ? nodes[modelKey] : {};

// Gather upstream descriptions for lineage context
const upstreamDescriptions = [];
for (const depId of (modelNode.depends_on?.nodes || [])) {
  const dep = nodes[depId];
  if (dep?.description) {
    upstreamDescriptions.push(`- ${dep.name}: ${dep.description}`);
  }
}

// Gather existing column definitions to avoid overwriting
const existingColumns = {};
for (const [colName, colData] of Object.entries(modelNode.columns || {})) {
  if (colData.description) {
    existingColumns[colName] = colData.description;
  }
}

return [{
  json: {
    modelName,
    filename: fileInfo.filename,
    repo: fileInfo.repo,
    branch: fileInfo.branch,
    sqlCode: typeof sqlContent === 'string' ? sqlContent : JSON.stringify(sqlContent),
    upstreamContext: upstreamDescriptions.join('\n') || 'No upstream models documented yet.',
    existingColumns: JSON.stringify(existingColumns, null, 2),
    materialization: modelNode.config?.materialized || 'view',
    schema: modelNode.schema || 'unknown'
  }
}];

