// Clean and validate the AI response
// Handle multiple AI response formats (Gemini, OpenAI, etc.)
const raw = $input.first().json;
const aiResponse = 
  raw.candidates?.[0]?.content?.parts?.[0]?.text ||  // Gemini format
  raw.message?.content ||                             // OpenAI format
  raw.text ||                                         // Generic
  raw.content ||                                      // Fallback
  '';

// Strip markdown code fences if present
let cleanYaml = aiResponse
  .replace(/^```ya?ml\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```\s*$/i, '')
  .trim();

// Basic validation
const isValid = cleanYaml.startsWith('version:') && cleanYaml.includes('models:');

if (!isValid) {
  return [{
    json: {
      valid: false,
      error: 'AI response did not produce valid schema.yml format',
      raw: aiResponse
    }
  }];
}

// Encode for GitHub API
const encoded = Buffer.from(cleanYaml).toString('base64');

return [{
  json: {
    valid: true,
    yaml: cleanYaml,
    yamlBase64: encoded,
    modelName: $('Build Lineage-Aware Agent Context').first().json.modelName,
    repo: $('Build Lineage-Aware Agent Context').first().json.repo,
    branch: $('Build Lineage-Aware Agent Context').first().json.branch,
    filename: $('Build Lineage-Aware Agent Context').first().json.filename
  }
}];
